text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "decisions": {
      "confirmed_decisions": [
        {
          "topic": "공개 릴리스 목표 시점",
          "decision": "스모크 테스트가 통과할 경우 금요일 15:00 KST를 공개 릴리스 목표 시점으로 둔다."
        },
        {
          "topic": "packageName mismatch 대응",
          "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토로 넘어간다."
        }
      ],
      "rejected_proposals": [
        {
          "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
          "result": "거절됨"
        }
      ],
      "internal_stretch_goals": [
        {
          "goal": "수요일 릴리스",
          "note": "내부 스트레치 골일 뿐이며 최종 공개 릴리스 결정은 아님"
        }
      ]
    },
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 의견이 있었지만 담당자는 지정되지 않음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있음"
      },
      {
        "risk": "README 설치 절차가 오래된 경우 릴리스 노트가 사용자에게 오해를 줄 수 있음"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 골을 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토",
      "due": "목요일까지 가능하면",
      "status": "미배정",
      "source_certainty": "중간"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 점검",
      "due": null,
      "status": "확정",
      "source_certainty": "높음"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 스모크 테스트 통과 여부",
      "스모크 실패 시 Doyun의 트리아지 노트 반영 상태",
      "생성된 tarball 경로의 정확성",
      "README 설치 절차 최신성",
      "최종 릴리스 승인 권한자 확정 여부",
      "릴리스 노트에 내부 수요일 스트레치 골을 언급할지 여부"
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "배정되지 않은 담당자",
      "명시되지 않은 추가 마감일"
    ]
  },
  "non_invention_rules": [
    "인라인 공개용 합성 회의 기록에 포함된 정보만 사용한다.",
    "확정 결정과 거절된 제안, 내부 스트레치 골, 리스크, 미해결 질문을 구분한다.",
    "고객, 예산, 보안, 장애, 법무, 담당자, 마감일 관련 사실은 기록에 없는 경우 추가하지 않는다.",
    "조건부 결정은 조건을 유지한 채 기록한다. 예: 스모크 테스트 통과 시 금요일 15:00 KST 공개 릴리스 목표.",
    "담당자나 기한이 없는 항목은 null 또는 미배정으로 남기고 추정하지 않는다."
  ]
}
